	type TareaEstado = 'pendiente' | 'en_proceso' | 'pausada' | 'completada';
	type Tarea = {
		id: string; folio: string; vin: string; modelo: string;
		proceso: string; frontera: string;
		estado: TareaEstado; hrsAcum: number; hrsEst: number;
